INSERT INTO campaign_reference (id, state, office_level, category, question, question_variants, answer, source_url, source_name, last_verified_date, update_frequency, verification_method, scope, import_batch_id) VALUES
  ('e73f3d88f65bda96', 'OR', '["federal","state","county"]', 'ballot_access', 'Does Oregon have an open or closed primary system?', '["How does the Oregon partisan primary work?","Can I vote in the Democratic primary if I am not registered as a Democrat?","Oregon closed primary rules 2026"]', 'Oregon uses a strictly closed primary system for partisan offices. Under ORS 254.365, only voters who are registered as members of a major political party may vote in that party''s primary. For the 2026 elections, the Democratic and Republican parties have opted to keep their primaries closed, meaning cross-party voting is prohibited.', 'https://sos.oregon.gov/voting/Pages/voteinor.aspx', 'Oregon Secretary of State - Voting in Oregon', '2026-05-14', 'per_cycle', 'official_source_direct', 'Voters and Campaigns', 'batch_2026-05-14T21-27-05_oregon_full_v1'),
  ('b96a8f3b545bc67d', 'OR', '["federal","state","county"]', 'voter_interaction', 'Can unaffiliated (NAV) voters participate in the Oregon primary?', '["What do Non-Affiliated Voters get on their ballot in Oregon?","Oregon primary voting for independents","NAV voter primary ballot Oregon"]', 'Non-Affiliated Voters (NAV)—Oregon''s term for independents—cannot vote in the Democratic or Republican partisan primaries. However, they do receive a primary ballot. The NAV ballot contains only nonpartisan races (such as judicial elections and the BOLI Commissioner) and local or state ballot measures.', 'https://sos.oregon.gov/voting/Pages/voteinor.aspx', 'Oregon Secretary of State - Voting in Oregon', '2026-05-14', 'static', 'official_source_direct', 'Unaffiliated voters', 'batch_2026-05-14T21-27-05_oregon_full_v1'),
  ('974aed01d7b6b20d', 'OR', '["federal","state","county"]', 'ballot_access', 'How does Oregon''s closed primary contrast with Washington''s Top-2 system?', '["Oregon vs Washington primary election differences","Do the top two vote getters advance in Oregon?","Partisan nomination process Oregon"]', 'Unlike Washington''s Top-2 primary—where all candidates run on one ballot and the top two advance regardless of party—Oregon''s closed partisan primaries strictly select party nominees. The winner of the Democratic primary advances to the general election to face the winner of the Republican primary, ensuring a partisan matchup in November.', 'https://sos.oregon.gov/elections/Pages/election-laws-rules-publications.aspx', 'Oregon Secretary of State - Election Laws', '2026-05-14', 'static', 'official_source_direct', 'Campaign strategists', 'batch_2026-05-14T21-27-05_oregon_full_v1'),
  ('e8c3545bc317217c', 'OR', '["federal","state","county"]', 'ballot_access', 'How do minor parties nominate candidates in Oregon?', '["Minor party ballot access Oregon","Do third parties have a primary in Oregon?","Nominating conventions for Oregon minor parties"]', 'Minor political parties in Oregon do not participate in the state-funded primary election. Instead, they nominate their candidates according to their own internal party bylaws, which typically involves a nominating convention. Once nominated, the party certifies the candidate''s name to the Secretary of State for placement on the November general election ballot.', 'https://sos.oregon.gov/elections/Pages/minor-political-parties.aspx', 'Oregon Secretary of State - Minor Political Parties', '2026-05-14', 'static', 'official_source_direct', 'Minor party candidates', 'batch_2026-05-14T21-27-05_oregon_full_v1'),
  ('d9a51ede680e7a05', 'OR', '["federal","state"]', 'election_dates', 'Which statewide and federal executive offices are on the 2026 Oregon ballot?', '["Is Tina Kotek running for re-election in 2026?","Oregon U.S. Senate race 2026","Who is top of the ticket in Oregon 2026?"]', 'In 2026, incumbent Governor Tina Kotek (D) is up for re-election for her second term. At the federal level, incumbent U.S. Senator Jeff Merkley (D) is defending his Class 2 seat. Additionally, the nonpartisan Bureau of Labor and Industries (BOLI) Commissioner is on the 2026 ballot.', 'https://sos.oregon.gov/elections/Pages/candidates.aspx', 'Oregon Secretary of State - Candidates', '2026-05-14', 'per_cycle', 'official_source_direct', 'Statewide and federal candidates', 'batch_2026-05-14T21-27-05_oregon_full_v1'),
  ('a297427c099c3e14', 'OR', '["federal","state"]', 'election_dates', 'Which statewide and federal offices are NOT on the 2026 Oregon ballot?', '["Is Ron Wyden on the ballot in 2026?","When is the next Oregon Attorney General election?","Are the SOS and Treasurer up for election in 2026?"]', 'U.S. Senator Ron Wyden (Class 3) is not on the 2026 ballot; his term runs through 2028. Furthermore, Oregon elects its other statewide executive officers—Secretary of State, Attorney General, and State Treasurer—on the presidential election cycle. Having just been elected in 2024, they will not be on the ballot again until 2028.', 'https://sos.oregon.gov/elections/Pages/candidates.aspx', 'Oregon Secretary of State - Candidates', '2026-05-14', 'per_cycle', 'official_source_direct', 'Statewide and federal candidates', 'batch_2026-05-14T21-27-05_oregon_full_v1'),
  ('ec1aa87fd91dba8d', 'OR', '["federal","state"]', 'election_dates', 'What is the 2026 election cycle for the Oregon State Legislature and U.S. House?', '["Are all Oregon House seats up in 2026?","Oregon Senate election cycle 2026","How many US House districts does Oregon have?"]', 'All 60 seats in the Oregon House of Representatives (2-year terms) are up for election in 2026. The Oregon State Senate (30 members, 4-year terms) will have approximately half of its districts on the ballot. Federally, all 6 of Oregon''s U.S. House of Representatives districts are up for election.', 'https://www.oregonlegislature.gov/', 'Oregon State Legislature', '2026-05-14', 'per_cycle', 'official_source_direct', 'Federal and legislative candidates', 'batch_2026-05-14T21-27-05_oregon_full_v1'),
  ('d488c1c344cc2b97', 'OR', '["federal","state","county"]', 'election_dates', 'When are the primary and general elections in Oregon for 2026?', '["Oregon primary date 2026","When is Election Day 2026 in Oregon?","May primary Oregon"]', 'The Oregon primary election will be held on Tuesday, May 19, 2026. The general election will be held on Tuesday, November 3, 2026.', 'https://sos.oregon.gov/elections/Pages/election-calendar.aspx', 'Oregon Secretary of State - Election Calendar', '2026-05-14', 'per_cycle', 'official_source_direct', 'All candidates', 'batch_2026-05-14T21-27-05_oregon_full_v1'),
  ('2d8a56cc4c4256f6', 'OR', '["federal","state","county","municipal"]', 'voter_interaction', 'Does Oregon allow same-day voter registration?', '["Can I register to vote on Election Day in Oregon?","Voter registration deadline Oregon 2026","Oregon 21-day registration cutoff"]', 'No. Oregon does not offer same-day or Election Day voter registration. Under ORS 247.025, the strict deadline to register to vote or to change party affiliation is 21 days before the election. For the May 19, 2026 primary, the registration cutoff is April 28, 2026.', 'https://sos.oregon.gov/voting/Pages/registration.aspx', 'ORS 247.025', '2026-05-14', 'static', 'statute_citation', 'Voters and GOTV teams', 'batch_2026-05-14T21-27-05_oregon_full_v1'),
  ('bd1d41c1c09e44e2', 'OR', '["federal","state","county","municipal"]', 'voter_interaction', 'How does Oregon Motor Voter assign party affiliation?', '["Automatic voter registration Oregon DMV","Do I get a party if I am registered at the DMV in Oregon?","Oregon Motor Voter defaults"]', 'Under the Oregon Motor Voter program, eligible citizens are automatically registered to vote when they obtain or renew a driver''s license at the DMV. By default, they are registered as Non-Affiliated Voters (NAV). They receive a mailer allowing them to opt out of registration entirely or to select a major political party to vote in closed primaries.', 'https://sos.oregon.gov/voting/Pages/motor-voter-faq.aspx', 'Oregon Secretary of State - Motor Voter FAQ', '2026-05-14', 'static', 'official_source_direct', 'Voters', 'batch_2026-05-14T21-27-05_oregon_full_v1'),
  ('9085c388bf054b20', 'OR', '["federal","state","county","municipal"]', 'voter_interaction', 'When are mail ballots sent out in Oregon?', '["Universal mail voting timeline Oregon","When do I get my ballot in the mail in OR?","Oregon vote-by-mail schedule"]', 'As a universal vote-by-mail state, Oregon automatically mails ballots to all active registered voters. Under ORS 254.470, county clerks must mail ballots between 14 and 18 days before the election. For the 2026 primary, ballots will begin arriving in early May.', 'https://sos.oregon.gov/voting/Pages/voteinor.aspx', 'ORS 254.470', '2026-05-14', 'static', 'statute_citation', 'Voters and Campaigns', 'batch_2026-05-14T21-27-05_oregon_full_v1'),
  ('db76560b9da43ba7', 'OR', '["federal","state","county","municipal"]', 'voter_interaction', 'What is the deadline to return a mail ballot in Oregon, and is there a postmark grace period?', '["Oregon ballot postmark rule","When is my Oregon ballot due?","HB 3291 ballot receipt deadline Oregon"]', 'Ballots must either be deposited in an official drop box by 8:00 p.m. on Election Day OR postmarked by the USPS by Election Day. Following the passage of HB 3291 (2021), Oregon now has a 7-day postmark grace period. Mailed ballots with a valid Election Day postmark will be counted if received by the county elections office within 7 days after the election.', 'https://sos.oregon.gov/voting/Pages/voteinor.aspx', 'Oregon Secretary of State - Vote in Oregon', '2026-05-14', 'static', 'official_source_direct', 'Voters and Campaigns', 'batch_2026-05-14T21-27-05_oregon_full_v1'),
  ('80ec2c1038de2bf8', 'OR', '["state","county","municipal"]', 'finance_ethics', 'What is ORESTAR in Oregon campaign finance?', '["Oregon campaign finance electronic filing system","Where do I report campaign donations in Oregon?","SOS ORESTAR portal"]', 'ORESTAR (Oregon Elections System for Tracking and Reporting) is the mandatory electronic filing system administered by the Oregon Secretary of State. All state and local candidates must use ORESTAR to register their campaign committees, file statements of organization, and disclose campaign contributions and expenditures.', 'https://sos.oregon.gov/elections/Pages/orestar.aspx', 'Oregon Secretary of State - ORESTAR', '2026-05-14', 'static', 'official_source_direct', 'All candidates and treasurers', 'batch_2026-05-14T21-27-05_oregon_full_v1'),
  ('4691ea43f6d911bd', 'OR', '["state","county"]', 'finance_ethics', 'Are there campaign contribution limits for Oregon state candidates in 2026?', '["Oregon individual donation caps 2026","HB 4024 effective date campaign finance","Can corporations donate to Oregon candidates?"]', 'No. For the 2026 election cycle, Oregon remains one of the few states with completely unlimited campaign contributions for state-level candidates, allowing unlimited donations from individuals, PACs, and corporations. However, under HB 4024 (passed in 2024), new strict contribution limits will become operative on January 1, 2027.', 'https://sos.oregon.gov/elections/Pages/campaign-finance-legislation.aspx', 'Oregon Secretary of State - HB 4024 Implementation', '2026-05-14', 'volatile', 'official_source_direct', 'State candidates and Donors', 'batch_2026-05-14T21-27-05_oregon_full_v1'),
  ('ae5caa197a2ec9ba', 'OR', '["state"]', 'recall_rules', 'Can state officials be recalled in Oregon?', '["Does Oregon have a recall for the Governor?","How to recall an Oregon state senator","Article II Section 18 recall Oregon"]', 'Yes. Oregon has a robust recall mechanism for state officials under Article II, Section 18 of the Oregon Constitution. Any public officer is subject to recall. Proponents must gather valid signatures equal to 15% of the total votes cast for Governor in the officer''s electoral district during the last gubernatorial election.', 'https://sos.oregon.gov/elections/Pages/recall.aspx', 'Oregon Constitution, Article II, Section 18', '2026-05-14', 'static', 'statute_citation', 'Statewide and legislative candidates', 'batch_2026-05-14T21-27-05_oregon_full_v1'),
  ('109b53fbe635c925', 'OR', '["state"]', 'candidate_eligibility', 'How does Measure 113 penalize legislative walkouts in Oregon?', '["Oregon unexcused absence penalty legislators","Are the 10 Republican senators barred from the 2026 ballot?","Article IV Section 15 Oregon Constitution"]', 'Under Measure 113 (Article IV, Section 15 of the OR Constitution), any state legislator who accumulates 10 or more unexcused absences from floor sessions is disqualified from holding office for the term immediately following their current term. The Oregon Supreme Court upheld this in 2024, barring multiple senators who walked out in 2023 from running for re-election when their current terms expire.', 'https://ballotpedia.org/Oregon_Measure_113,_Exclusion_from_Re-election_for_Legislative_Absenteeism_Initiative_(2022)', 'Oregon Constitution, Article IV, Section 15', '2026-05-14', 'static', 'statute_citation', 'State legislative candidates', 'batch_2026-05-14T21-27-05_oregon_full_v1'),
  ('0a6da4f8956f750c', 'OR', '["state"]', 'candidate_eligibility', 'Does Oregon have legislative term limits?', '["How many terms can an Oregon state senator serve?","Are there term limits for the Oregon House?","Oregon term limit laws"]', 'No. Currently, Oregon does not have legislative term limits. Voters passed term limits in 1992, but the Oregon Supreme Court struck them down in 2002 on technical grounds. Attempts to reinstate them have not succeeded, meaning incumbents can serve indefinitely.', 'https://ballotpedia.org/Oregon_State_Legislature', 'Oregon State Legislature - Ballotpedia', '2026-05-14', 'static', 'secondary_source', 'State legislative candidates', 'batch_2026-05-14T21-27-05_oregon_full_v1'),
  ('d4c8cc972eadd54b', 'OR', '["federal","state"]', 'runoff_rules', 'Does Oregon use Ranked Choice Voting (RCV) statewide?', '["Did Measure 117 pass in Oregon?","Ranked Choice Voting Oregon 2026","Does the state of Oregon use RCV?"]', 'No. While voters in some local jurisdictions (like Portland, Multnomah County, and Benton County) use Ranked Choice Voting, a statewide measure to adopt RCV for federal and state executive races (Measure 117) was defeated by voters in November 2024 (57.7% voted No). Plurality voting remains standard statewide.', 'https://ballotpedia.org/Oregon_Measure_117,_Ranked-Choice_Voting_for_Federal_and_State_Elections_Measure_(2024)', 'Oregon Measure 117 (2024)', '2026-05-14', 'volatile', 'secondary_source', 'All statewide and federal candidates', 'batch_2026-05-14T21-27-05_oregon_full_v1'),
  ('c474b6543c93c57c', 'OR', '["state"]', 'ballot_access', 'What are the signature thresholds for citizen initiatives in Oregon for 2026?', '["How many signatures to get on the Oregon ballot?","Oregon initiative signature requirement 2026","Constitutional amendment vs statute signature count Oregon"]', 'In Oregon, signature requirements are based on the total votes cast in the 2022 gubernatorial election. For 2026, an initiated state statute requires signatures equal to 6% of that vote (117,173 valid signatures). A constitutional amendment requires 8% (156,231 valid signatures). Referendums require 4% (78,116 signatures).', 'https://sos.oregon.gov/elections/documents/stateir.pdf', 'Oregon Secretary of State - State Initiative and Referendum Manual', '2026-05-14', 'per_cycle', 'official_source_direct', 'Ballot measure committees', 'batch_2026-05-14T21-27-05_oregon_full_v1'),
  ('d00bc909c3a5c282', 'OR', '["state"]', 'candidate_eligibility', 'What are the age and residency requirements to run for Governor of Oregon?', '["How old do you have to be to be Governor of OR?","Oregon Governor residency requirements","Qualifications for Oregon Governor"]', 'Under Article V, Section 2 of the Oregon Constitution, a candidate for Governor must be a citizen of the United States, at least 30 years of age, and a resident of Oregon for at least three years immediately preceding the election.', 'https://www.oregonlegislature.gov/bills_laws/Pages/OrConst.aspx', 'Oregon Constitution, Article V, Section 2', '2026-05-14', 'static', 'statute_citation', 'Gubernatorial candidates', 'batch_2026-05-14T21-27-05_oregon_full_v1'),
  ('4371c79ccf53c0cf', 'OR', '["state"]', 'candidate_eligibility', 'What are the age and residency requirements to run for the Oregon State Legislature?', '["Qualifications for OR State Representative","Residency requirement Oregon State Senate","Do I have to live in my district to run in OR?"]', 'Under Article IV, Section 8 of the Oregon Constitution, a candidate for the state legislature must be a citizen of the United States, at least 21 years of age, and a resident of the legislative district they seek to represent for at least one year immediately prior to the election.', 'https://www.oregonlegislature.gov/bills_laws/Pages/OrConst.aspx', 'Oregon Constitution, Article IV, Section 8', '2026-05-14', 'static', 'statute_citation', 'State legislative candidates', 'batch_2026-05-14T21-27-05_oregon_full_v1'),
  ('b979517337d6c2fb', 'OR', '["state"]', 'ballot_access', 'How is a vacancy in the Oregon State Legislature filled?', '["Who appoints a replacement State Senator in OR?","Legislative vacancy committee Oregon","Special election for OR House vacancy"]', 'Under ORS 171.051, a state legislative vacancy is filled by appointment, not a special election. The political party of the vacating member submits a list of 3 to 5 nominees. The county commissioners of the affected district then appoint one of those nominees to serve out the remainder of the term (or until the next general election).', 'https://oregon.public.law/statutes/ors_171.051', 'ORS 171.051', '2026-05-14', 'static', 'statute_citation', 'State legislative candidates', 'batch_2026-05-14T21-27-05_oregon_full_v1'),
  ('cf5199dc70cf2a30', 'OR', '["federal"]', 'ballot_access', 'How is a vacancy in an Oregon U.S. Senate seat filled?', '["Governor appointment US Senate Oregon","Special election for US Senate OR","Oregon rule for replacing a US Senator"]', 'Under ORS 188.120, the Governor of Oregon fills a U.S. Senate vacancy by appointment. The appointee must be from the same political party as the vacating senator and must have been affiliated with that party for at least 180 days prior to the vacancy. The appointee serves until a special election is held.', 'https://law.justia.com/codes/oregon/volume-05/chapter-188/section-188-120/', 'ORS 188.120', '2026-05-14', 'static', 'statute_citation', 'Federal candidates', 'batch_2026-05-14T21-27-05_oregon_full_v1'),
  ('0943d0feb4b2b082', 'OR', '["state"]', 'candidate_eligibility', 'What is the BOLI Commissioner and why is it on all Oregon primary ballots?', '["Bureau of Labor and Industries election Oregon","Is the Oregon BOLI race partisan?","Can a candidate win the BOLI race outright in the primary?"]', 'The Bureau of Labor and Industries (BOLI) Commissioner is a nonpartisan statewide executive office in Oregon. Because it is nonpartisan, all registered voters—including unaffiliated (NAV) voters—can vote in this primary race. Under ORS 249.088, if a candidate wins a majority (over 50%) of the vote in the May primary, they win the election outright; otherwise, the top two advance to November.', 'https://sos.oregon.gov/elections/Pages/candidates.aspx', 'ORS 249.088', '2026-05-14', 'static', 'official_source_direct', 'Statewide candidates', 'batch_2026-05-14T21-27-05_oregon_full_v1'),
  ('3e45287bc6931dfb', 'OR', '["state"]', 'ballot_access', 'What is Oregon Ballot Measure 120 on the 2026 primary ballot?', '["Gas tax referendum Oregon 2026","HB 3991 veto referendum","What is the transportation tax measure on the May ballot?"]', 'Measure 120 is a citizen veto referendum on House Bill 3991, which increases the state gas tax and vehicle registration fees. Placed on the May 19, 2026 primary ballot, a ''yes'' vote upholds the tax increases to fund transportation, while a ''no'' vote repeals them. Because it is a ballot measure, all voters (including unaffiliated voters) may vote on it.', 'https://ballotpedia.org/Oregon_Referendum_120,_Increase_to_Gas_Tax,_Payroll_Tax,_and_Vehicle_Registration_Fees_Referendum_(May_2026)', 'Oregon Referendum 120 (2026)', '2026-05-14', 'volatile', 'secondary_source', 'Ballot measure committees and Voters', 'batch_2026-05-14T21-27-05_oregon_full_v1'),
  ('efcac354def56336', 'OR', '["state","county","municipal"]', 'finance_ethics', 'When must an Oregon candidate register a campaign committee in ORESTAR?', '["Oregon campaign committee registration threshold","When do I have to file a Statement of Organization in OR?","ORESTAR $750 registration limit"]', 'A candidate must form a candidate committee and file a Statement of Organization with the Elections Division via ORESTAR within three business days of first receiving a contribution or making an expenditure, UNLESS they elect to serve as their own treasurer and do not expect to receive or spend more than $750 during the calendar year (including personal funds).', 'https://sos.oregon.gov/elections/Pages/orestar.aspx', 'Oregon Secretary of State - ORESTAR', '2026-05-14', 'static', 'official_source_direct', 'All candidates', 'batch_2026-05-14T21-27-05_oregon_full_v1'),
  ('e90c61e4c760699a', 'OR', '["state","county","municipal"]', 'finance_ethics', 'Are candidate committee funds prohibited from being used for personal expenses in Oregon?', '["OR personal use prohibition campaign finance","Can I use campaign money for personal items in Oregon?","Prohibited expenditures Oregon campaign finance ORS 260.407"]', 'Yes. Under ORS 260.407, campaign funds may not be converted by any person to any personal use. They must be used to defray expenses incurred in connection with the candidate''s campaign or duties as a public official. Exceptions allow for the repayment of personal campaign loans, charitable donations, and transfers to political parties.', 'https://oregon.public.law/statutes/ors_260.407', 'ORS 260.407', '2026-05-14', 'static', 'statute_citation', 'All candidates', 'batch_2026-05-14T21-27-05_oregon_full_v1'),
  ('655cce5b9abf5799', 'OR', '["state","county","municipal"]', 'finance_ethics', 'What is the 2026 campaign finance reporting schedule for Oregon candidates?', '["OR campaign finance filing dates 2026","When are ORESTAR reports due for Oregon 2026 primary?","Oregon pre-primary and pre-general report deadlines"]', 'Oregon operates a continuous transaction-based reporting system via ORESTAR rather than just filing broad quarterly summaries. Standard transactions must be filed within 30 days. However, during the specific election windows (starting 42 days before the May primary and 42 days before the November general election), the deadline accelerates, and transactions must be filed within 7 calendar days.', 'https://sos.oregon.gov/elections/Documents/current-elections-calendar.pdf', 'Oregon Secretary of State - Elections Calendar', '2026-05-14', 'per_cycle', 'official_source_direct', 'All candidates', 'batch_2026-05-14T21-27-05_oregon_full_v1'),
  ('12b8ba626dce3b91', 'OR', '["state","county","municipal"]', 'finance_ethics', 'What are the rules for a candidate loaning personal funds to their own campaign in Oregon?', '["Oregon candidate personal loan limits","Can I pay myself back for a campaign loan in OR?","Reporting candidate loans in ORESTAR"]', 'Candidates may loan their own personal funds to their campaign. Because Oregon currently has no contribution limits for state campaigns, there is no cap on self-funding or personal loans. Loans must be properly disclosed as such in ORESTAR, and candidates may use future campaign contributions to repay the loan under ORS 260.407.', 'https://oregon.public.law/statutes/ors_260.407', 'ORS 260.407', '2026-05-14', 'static', 'statute_citation', 'All candidates', 'batch_2026-05-14T21-27-05_oregon_full_v1'),
  ('494973e43b668ddd', 'OR', '["state","county","municipal"]', 'finance_ethics', 'How are in-kind contributions valued and reported in Oregon''s ORESTAR system?', '["Oregon in-kind contribution valuation rules","Reporting non-monetary donations Oregon campaign","Fair market value for in-kind gifts ORS 260.064"]', 'In-kind contributions must be reported in ORESTAR at their fair market value—the price the candidate would have paid for the item or service. If a candidate or committee receives updated information that an in-kind contribution''s value differs from what was initially reported, they must update the filing under ORS 260.064.', 'https://oregon.public.law/statutes/ors_260.064', 'ORS 260.064', '2026-05-14', 'static', 'statute_citation', 'All candidates', 'batch_2026-05-14T21-27-05_oregon_full_v1'),
  ('73b4eaec8e7e2a8f', 'OR', '["state","county","municipal"]', 'finance_ethics', 'When does outside spending become prohibited coordination in Oregon?', '["OR campaign coordination rules","When is a PAC expenditure not independent in Oregon?","Prohibition on candidate-PAC coordination ORS 260.005"]', 'Under ORS 260.005, an expenditure is considered ''coordinated'' (and thus a controlled contribution rather than an independent expenditure) if it is made with the cooperation, prior consent, consultation, or at the request or suggestion of a candidate or their agent. A ''controlled committee'' is one whose actions are directly or indirectly influenced by the candidate.', 'https://oregon.public.law/statutes/ors_260.005', 'ORS 260.005', '2026-05-14', 'static', 'statute_citation', 'All candidates and IECs', 'batch_2026-05-14T21-27-05_oregon_full_v1'),
  ('dbf90cc4ff8f2541', 'OR', '["state","county","municipal"]', 'finance_ethics', 'What are the late filing penalties for campaign finance reports in Oregon?', '["OR ORESTAR late fee","Penalty for missing an Oregon campaign finance deadline","Secretary of State fine for late filing ORS 260.232"]', 'The Secretary of State may impose civil penalties for failing to file or late filing of transactions in ORESTAR under ORS 260.232. The penalty is typically up to 10% of the late transaction amount per violation, though the Secretary has the authority to reduce penalties upon a showing of mitigating circumstances after a hearing request.', 'https://oregon.public.law/statutes/ors_260.232', 'ORS 260.232', '2026-05-14', 'static', 'statute_citation', 'All candidates and treasurers', 'batch_2026-05-14T21-27-05_oregon_full_v1'),
  ('de94b7c95722f656', 'OR', '["state","county","municipal"]', 'finance_ethics', 'When and how must a candidate committee be terminated in Oregon?', '["Closing a Oregon campaign committee","ORESTAR committee termination requirements","Final campaign finance report Oregon"]', 'A committee may be discontinued in ORESTAR only when it has achieved a zero balance and has no outstanding debts or obligations. To officially close the committee, the treasurer or candidate must file a final transaction to zero out the account and formally discontinue the Statement of Organization within the ORESTAR portal.', 'https://sos.oregon.gov/elections/documents/orestartransfiling.pdf', 'Oregon Secretary of State - ORESTAR Manual', '2026-05-14', 'static', 'official_source_direct', 'All candidates', 'batch_2026-05-14T21-27-05_oregon_full_v1'),
  ('abce42c4f5fcedce', 'OR', '["state","county","municipal"]', 'finance_ethics', 'What are the disclosure rules for independent expenditures in Oregon?', '["OR independent expenditure reporting ORS 260.044","Disclosure for OR independent expenditure groups","Reporting thresholds for outside spending Oregon"]', 'Under ORS 260.044, if a person or entity makes independent expenditures totaling more than $250 in a calendar year, they must report it in ORESTAR within 7 days. If the expenditure occurs within the 42-day window prior to a primary or general election, it must be reported within 7 days; if filed very close to the election, special tight deadlines apply to ensure voters are informed before voting.', 'https://oregon.public.law/statutes/ors_260.044', 'ORS 260.044', '2026-05-14', 'static', 'statute_citation', 'Independent groups and PACs', 'batch_2026-05-14T21-27-05_oregon_full_v1'),
  ('00899d711a6ed773', 'OR', '["state","county"]', 'finance_ethics', 'What new contribution limits will take effect in Oregon under HB 4024 on January 1, 2027?', '["Oregon HB 4024 limits 2027","How much can an individual donate under the new Oregon law?","Future campaign finance limits Oregon"]', 'While the 2026 cycle remains unlimited, HB 4024 imposes strict limits starting January 1, 2027. Under the new law, individuals and corporations will be capped at giving $3,300 per election to statewide candidates, state senators, state representatives, circuit court judges, and district attorneys.', 'https://olis.oregonlegislature.gov/liz/2024R1/Downloads/MeasureAnalysisDocument/82649', 'Oregon Legislative Information System - HB 4024 Summary', '2026-05-14', 'static', 'official_source_direct', 'State and County candidates', 'batch_2026-05-14T21-27-05_oregon_full_v1'),
  ('2b830e2707551459', 'OR', '["state","county"]', 'finance_ethics', 'Does Oregon state provide public financing or matching funds for state campaigns?', '["Public matching funds for Oregon candidates","State funded campaigns Oregon status","Clean elections program Oregon state"]', 'No. Oregon state does not have a public financing or matching funds program for state-level candidates (Governor, Legislature, etc.). Campaigns are funded entirely through private contributions. However, at the municipal level, the City of Portland operates the ''Open and Accountable Elections Program'' providing a 9-to-1 match for small-dollar donations to qualified city candidates.', 'https://www.portland.gov/auditor/elections/documents/faq-pcc-chapter-210/download', 'City of Portland Elections', '2026-05-14', 'static', 'official_source_direct', 'State and Municipal candidates', 'batch_2026-05-14T21-27-05_oregon_full_v1'),
  ('dc0c48cb23c8ef9d', 'OR', '["state","county","municipal"]', 'finance_ethics', 'Are corporate contributions allowed to Oregon candidates in 2026?', '["Corporate contribution ban Oregon state","Can a business donate to my campaign in OR?","Corporate campaign finance rules Oregon"]', 'Yes. For the 2026 cycle, Oregon allows direct corporate contributions to state and local candidate campaigns in unlimited amounts. However, candidates should be aware that under the newly enacted HB 4024, corporate contributions will be subject to strict caps (e.g., $3,300 per election) beginning on January 1, 2027.', 'https://sos.oregon.gov/elections/Documents/campaign-finance-manual.pdf', 'Oregon Secretary of State - Campaign Finance Manual', '2026-05-14', 'volatile', 'official_source_direct', 'Candidates and Businesses', 'batch_2026-05-14T21-27-05_oregon_full_v1'),
  ('9531765528975a6e', 'OR', '["state"]', 'finance_ethics', 'What are the restrictions on contributions from registered lobbyists in Oregon?', '["OR lobbyist donation ban","Can a lobbyist give to an Oregon legislator?","Lobbyist contribution session freeze Oregon"]', 'Unlike some states that have a strict ''session freeze,'' Oregon does not currently have a blanket prohibition preventing lobbyists from making campaign contributions to state legislators during the legislative session. Lobbyists may contribute just as any other individual or entity in the state.', 'https://sos.oregon.gov/elections/Documents/campaign-finance-manual.pdf', 'Oregon Secretary of State - Campaign Finance Manual', '2026-05-14', 'static', 'official_source_direct', 'Legislative candidates', 'batch_2026-05-14T21-27-05_oregon_full_v1'),
  ('702b659a17160684', 'OR', '["federal"]', 'candidate_eligibility', 'What are the eligibility requirements for U.S. House and Senate candidates in Oregon?', '["US Senate residency requirements Oregon","Age to run for Congress in Oregon","Federal constitutional requirements for OR candidates"]', 'Federal candidates must meet U.S. Constitutional requirements: U.S. House members must be at least 25 years old, a U.S. citizen for 7 years, and an inhabitant of the state when elected. U.S. Senators must be 30 years old, a U.S. citizen for 9 years, and an inhabitant of the state when elected. District residency is not required for the U.S. House.', 'https://sos.oregon.gov/elections/Pages/election-laws-rules-publications.aspx', 'Oregon Secretary of State - Elections Division', '2026-05-14', 'static', 'official_source_direct', 'Federal candidates', 'batch_2026-05-14T21-27-05_oregon_full_v1'),
  ('42ffb165e3072890', 'OR', '["state"]', 'candidate_eligibility', 'What are the eligibility requirements for the Oregon Secretary of State and Treasurer?', '["Requirements to run for OR Secretary of State","Eligibility for Oregon State Treasurer","Who can run for Secretary of State in OR?"]', 'Under Article VI, Section 1 of the Oregon Constitution, the Secretary of State and Treasurer must be elected by the ''qualified electors of the State.'' There are no specific professional degrees required; the candidate must simply be a U.S. citizen and an eligible registered voter of Oregon.', 'https://www.oregonlegislature.gov/bills_laws/Pages/OrConst.aspx', 'Oregon Constitution, Article VI, Section 1', '2026-05-14', 'static', 'statute_citation', 'Statewide candidates', 'batch_2026-05-14T21-27-05_oregon_full_v1'),
  ('83bc58271b775091', 'OR', '["state"]', 'candidate_eligibility', 'Does the Oregon Attorney General have to be a licensed attorney?', '["Qualifications to run for Attorney General in OR","Do I need to be a member of the bar to be OR AG?","Legal requirements for Oregon Attorney General"]', 'Yes. To practice law and represent the state in legal matters in Oregon, an individual must be an active member in good standing of the Oregon State Bar. Therefore, the Attorney General must be a licensed attorney who has passed the bar examination approved by the Oregon Supreme Court.', 'https://www.osbar.org/public/legalinfo/932.htm', 'Oregon State Bar', '2026-05-14', 'static', 'official_source_direct', 'Statewide candidates', 'batch_2026-05-14T21-27-05_oregon_full_v1'),
  ('6e3ded861c586612', 'OR', '["county"]', 'candidate_eligibility', 'What are the eligibility requirements for an elected County Sheriff in Oregon?', '["Qualifications for OR County Sheriff","Can anyone run for Sheriff in Oregon?","Oregon county official requirements ORS 206"]', 'Under ORS 204.016 and 206.015, a candidate for Sheriff must be a U.S. citizen, at least 21 years old, and a resident/elector of the county. They must also have at least four years of full-time law enforcement experience (or two years plus post-high school education) and no felony convictions that would prevent state police certification.', 'https://oregon.public.law/statutes/ors_204.016', 'ORS 204.016', '2026-05-14', 'static', 'statute_citation', 'County candidates', 'batch_2026-05-14T21-27-05_oregon_full_v1'),
  ('1ce624285df8e0d8', 'OR', '["judicial"]', 'candidate_eligibility', 'Are Circuit Court judges elected or appointed in Oregon, and what are the qualifications?', '["Oregon Circuit Court judge eligibility","Do judges run for election in OR?","Qualifications to run for judge in Oregon"]', 'Oregon Circuit Court judges are elected to six-year terms in nonpartisan elections. To serve, a judge must be a U.S. citizen, a state resident for at least three years, a resident of their judicial district for at least one year, a member of the Oregon State Bar, and under the mandatory retirement age of 75.', 'https://www.courts.oregon.gov/about/Pages/default.aspx', 'Oregon Judicial Branch', '2026-05-14', 'static', 'official_source_direct', 'Judicial candidates', 'batch_2026-05-14T21-27-05_oregon_full_v1'),
  ('b64c4cf6ed0730b1', 'OR', '["federal","state","county","municipal"]', 'voter_interaction', 'What is the electioneering buffer zone distance at Oregon ballot drop boxes?', '["How close can I campaign to a drop box in OR?","Buffer zone around voting centers Oregon","ORS 260.695 electioneering rules"]', 'Under ORS 260.695, it is illegal to do any electioneering (including circulating cards, handbills, or soliciting signatures) within any building containing a designated official ballot drop box, or within 100 feet measured radially from the entrance to that building or standalone drop box. It is also illegal to obstruct access to a drop box.', 'https://oregon.public.law/statutes/ors_260.695', 'ORS 260.695', '2026-05-14', 'static', 'statute_citation', 'Campaign workers and Voters', 'batch_2026-05-14T21-27-05_oregon_full_v1'),
  ('0491afa1dca275a6', 'OR', '["federal","state","county","municipal"]', 'voter_interaction', 'What is the ballot signature cure process and deadline in Oregon?', '["How to fix a rejected signature in OR","Oregon ballot cure process deadline","Missing signature on OR mail ballot"]', 'If a ballot envelope is missing a signature or the signature does not match the voter registration record, the county elections office sends a letter to the voter. The voter has up to 21 days after the election to provide a matching signature or fix the issue so their ballot can be tabulated.', 'https://sos.oregon.gov/voting/Pages/voteinor.aspx', 'Oregon Secretary of State', '2026-05-14', 'static', 'official_source_direct', 'Voters and Campaigns', 'batch_2026-05-14T21-27-05_oregon_full_v1'),
  ('98419e1ae1d5225a', 'OR', '["federal","state","county","municipal"]', 'voter_interaction', 'Can campaigns purchase the voter file from the state in Oregon?', '["Oregon voter database access","How to get the voter list in OR","Cost of voter registration data Oregon"]', 'Yes. Campaigns and political committees can request an electronic copy of the statewide voter list from the Secretary of State''s Elections Division. Unlike some states where it is free, Oregon charges a setup fee of $25 plus $0.025 per 100 voter records (with a maximum fee of $500).', 'https://sos.oregon.gov/elections/Pages/data-research.aspx', 'Oregon Secretary of State - Data and Research', '2026-05-14', 'static', 'official_source_direct', 'Campaign Strategists', 'batch_2026-05-14T21-27-05_oregon_full_v1'),
  ('1422753addd3bb16', 'OR', '["federal","state","county","municipal"]', 'voter_interaction', 'What are the deadlines for military and overseas (UOCAVA) voters in Oregon?', '["When are military ballots due in Oregon?","UOCAVA return deadline OR","Overseas voting rules Oregon state"]', 'Under UOCAVA, ballots are mailed to military and overseas voters at least 45 days before an election. Voters may return their ballots by mail, or they may fax or email a signed ballot if they include a Secret Ballot Waiver Form. Ballots must be received, or mailed with a valid postmark, by 8:00 p.m. on Election Day.', 'https://sos.oregon.gov/voting/Pages/militaryoverseas.aspx', 'Oregon Secretary of State - Military & Overseas Voters', '2026-05-14', 'static', 'official_source_direct', 'UOCAVA voters', 'batch_2026-05-14T21-27-05_oregon_full_v1'),
  ('65153341da186d2d', 'OR', '["federal","state","county","municipal"]', 'voter_interaction', 'Does Oregon restore voting rights to individuals with felony convictions?', '["Can felons vote in Oregon state?","Felony voting rights restoration OR","Voting on parole in Oregon ORS 137.281"]', 'Yes. Under ORS 137.281, an individual convicted of a felony only loses their right to vote while they are actively incarcerated in a prison or county jail serving their sentence. Their voting rights are automatically restored immediately upon discharge or release to parole/probation, but they must re-register to vote.', 'https://oregon.public.law/statutes/ors_137.281', 'ORS 137.281', '2026-05-14', 'static', 'statute_citation', 'Voters', 'batch_2026-05-14T21-27-05_oregon_full_v1'),
  ('e8ec54bf56231e6e', 'OR', '["federal","state","county","municipal"]', 'voter_interaction', 'When are provisional ballots used in Oregon''s mail ballot system?', '["What is a provisional ballot in OR?","Voting in person with a lost ballot Oregon","When do election workers issue provisional ballots OAR 115?"]', 'Because Oregon is a universal mail-voting state, provisional ballots are rare but exist. If an individual believes they are eligible to vote but did not receive their mail ballot, they may request a provisional ballot at a county elections office. These are securely held and counted only if the voter''s registration and eligibility are confirmed post-election.', 'https://sos.oregon.gov/voting/Pages/voteinor.aspx', 'Oregon Secretary of State', '2026-05-14', 'static', 'official_source_direct', 'Voters and Poll Watchers', 'batch_2026-05-14T21-27-05_oregon_full_v1'),
  ('385e219460990d1b', 'OR', '["federal","state","county","municipal"]', 'voter_interaction', 'How does Oregon maintain its voter registration lists?', '["OR voter list maintenance rules","How are inactive voters handled in Oregon?","ERIC system Oregon state NVRA"]', 'The Oregon Secretary of State maintains the Oregon Centralized Voter Registration (OCVR) database. Under NVRA requirements, the state updates addresses using USPS Change of Address data and DMV records. If a voter moves out of state or mail is returned undeliverable, the state sends a forwardable Confirmation Notice. If unreturned, the voter is marked ''inactive'' and will be canceled if they do not vote in the next two federal elections.', 'https://sos.oregon.gov/elections/Documents/Directive-2026-01-List-Maintenance.pdf', 'Oregon SOS Directive 2026-01 (Voter List Maintenance)', '2026-05-14', 'static', 'official_source_direct', 'Voters and Campaigns', 'batch_2026-05-14T21-27-05_oregon_full_v1')
INSERT INTO campaign_reference (id, state, office_level, category, question, question_variants, answer, source_url, source_name, last_verified_date, update_frequency, verification_method, scope, import_batch_id) VALUES
  ('973ce84658085f93', 'OR', '["federal","state"]', 'redistricting', 'Who is responsible for drawing Oregon''s legislative and congressional maps?', '["Does Oregon use an independent redistricting commission?","Who has the authority to draw district lines in Oregon?","Redistricting process Oregon"]', 'In Oregon, the state legislature has the primary authority to draw both congressional and state legislative districts. If the legislature fails to pass state legislative maps by the statutory deadline, the responsibility falls to the Secretary of State. Congressional maps, however, must be passed by the legislature or potentially resolved by the courts. Maps are subject to gubernatorial veto and judicial review.', 'https://www.oregonlegislature.gov/redistricting', 'Oregon State Legislature - Redistricting', '2026-05-14', 'static', 'official_source_direct', 'All federal and state candidates', 'batch_2026-05-14T21-27-05_oregon_full_v1'),
  ('07987ef74fc6a2fd', 'OR', '["federal","state"]', 'redistricting', 'What are the legal criteria for redistricting in Oregon?', '["Standards for drawing Oregon district lines","ORS 188.010 redistricting criteria","Oregon gerrymandering rules"]', 'Under ORS 188.010, maps must be drawn to: (1) be contiguous, (2) utilize existing geographic or political boundaries, (3) be as compact as possible, and (4) not divide communities of common interest. Furthermore, maps cannot be drawn for the purpose of favoring a political party, incumbent, or other person, nor can they be drawn to dilute the voting strength of any language or ethnic minority group.', 'https://oregon.public.law/statutes/ors_188.010', 'ORS 188.010', '2026-05-14', 'static', 'statute_citation', 'All federal and state candidates', 'batch_2026-05-14T21-27-05_oregon_full_v1'),
  ('974f9aa91e56815a', 'OR', '["federal","state"]', 'redistricting', 'Are the current Oregon district maps operative for the 2026 election cycle?', '["Status of 2021 Oregon redistricting maps","Are there pending redistricting lawsuits in Oregon?","Oregon 2026 district boundaries"]', 'Yes. The maps passed by the legislature during the 2021 special session and upheld by the Oregon Supreme Court in early 2022 (following challenges to both congressional and state legislative lines) remain in effect and are fully operative for the 2026 election cycle.', 'https://sos.oregon.gov/elections/Pages/maps.aspx', 'Oregon Secretary of State - Maps', '2026-05-14', 'static', 'official_source_direct', 'All federal and state candidates', 'batch_2026-05-14T21-27-05_oregon_full_v1'),
  ('b27fb6c743256a2b', 'OR', '["state"]', 'ballot_access', 'What voter approval threshold is required to pass a citizen initiative in Oregon?', '["Oregon initiative pass threshold","Does a measure need a supermajority in Oregon?","Majority vote requirements Oregon ballot measures"]', 'Generally, Oregon requires only a simple majority (50% plus one vote) to pass both initiated state statutes and constitutional amendments. Unlike Colorado, there is no general 55% supermajority requirement for constitutional changes. However, any measure that itself creates a new supermajority requirement for future actions must be passed by that same supermajority percentage.', 'https://sos.oregon.gov/elections/Pages/statemanual.aspx', 'Oregon State Initiative and Referendum Manual', '2026-05-14', 'static', 'official_source_direct', 'Ballot measure committees', 'batch_2026-05-14T21-27-05_oregon_full_v1'),
  ('7dfdb7a22599465c', 'OR', '["state"]', 'ballot_access', 'How does the Oregon legislature refer measures to the voters?', '["Legislative referral process Oregon","Referendum by legislature ORS","Can the OR legislature put a law on the ballot?"]', 'The Oregon Legislature may refer a proposed law or constitutional amendment to the voters by passing a joint resolution or a bill with a referral clause. This process, known as a legislative referral, requires a simple majority vote in both the House and Senate and does not require the Governor''s signature.', 'https://sos.oregon.gov/elections/Pages/statemanual.aspx', 'Oregon Secretary of State - Referrals', '2026-05-14', 'static', 'official_source_direct', 'Statewide candidates and strategists', 'batch_2026-05-14T21-27-05_oregon_full_v1'),
  ('cf6c4324f109c772', 'OR', '["state"]', 'ballot_access', 'What is the Oregon Citizens'' Initiative Review (CIR)?', '["CIR process Oregon","How does the voter guide initiative review work?","Independent panel review Oregon ballot measures"]', 'The CIR is a unique Oregon process (established by SB 223 in 2011) where an independent, nonpartisan panel of randomly selected voters reviews specific high-profile initiatives. The panel hears from proponents, opponents, and experts, then writes a ''Citizens'' Statement'' summarizing key facts and arguments, which is published in the official Voters'' Pamphlet to assist all voters.', 'https://www.oregon.gov/circ/Pages/index.aspx', 'Oregon Citizens'' Initiative Review Commission', '2026-05-14', 'static', 'official_source_direct', 'Ballot measure committees and Voters', 'batch_2026-05-14T21-27-05_oregon_full_v1'),
  ('8ba6a51da7960277', 'OR', '["state"]', 'ballot_access', 'Are there geographic distribution requirements for initiative signatures in Oregon?', '["Oregon initiative signature distribution rules","Can I get all signatures from Portland for an OR initiative?","Does Oregon have a 2 percent per district rule?"]', 'No. Unlike some states like Colorado or Nevada, Oregon has no geographic distribution requirement for initiative or referendum signatures. All required signatures may legally be collected from a single county or city, provided the signers are registered voters in the state of Oregon.', 'https://sos.oregon.gov/elections/Pages/statemanual.aspx', 'Oregon Secretary of State - Initiative Manual', '2026-05-14', 'static', 'official_source_direct', 'Ballot measure committees', 'batch_2026-05-14T21-27-05_oregon_full_v1'),
  ('9e52f3373f5107d6', 'OR', '["state"]', 'ballot_access', 'How long do proponents have to circulate an initiative petition in Oregon?', '["Oregon initiative circulation period","Deadline to gather signatures for Oregon measures","Initiative timeline Oregon"]', 'The circulation period for a citizen initiative can last up to approximately two years. Proponents can begin collecting signatures once the petition is approved for circulation by the Secretary of State. All signatures must be filed with the Secretary of State no later than four months before the general election (for 2026, the deadline is July 3, 2026).', 'https://sos.oregon.gov/elections/Pages/statemanual.aspx', 'Oregon Secretary of State - Signature Deadlines', '2026-05-14', 'per_cycle', 'official_source_direct', 'Ballot measure committees', 'batch_2026-05-14T21-27-05_oregon_full_v1'),
  ('c3306cfedb843f8c', 'OR', '["municipal"]', 'voter_interaction', 'What is the ''double majority'' rule for local measures in Oregon?', '["Oregon 50 percent turnout rule","Double majority tax measures Oregon","Does Measure 56 affect local elections?"]', 'The ''double majority'' rule required certain local property tax measures to receive both a majority of ''yes'' votes and at least 50% voter turnout to pass. However, following Measure 56 (2008), this rule now applies only to local elections held in May or November of odd-numbered years, or other special elections. It does not apply to general elections in even-numbered years.', 'https://sos.oregon.gov/elections/Pages/manuals-forms.aspx', 'Oregon Secretary of State - County, City and District Manual', '2026-05-14', 'static', 'official_source_direct', 'Local candidates and measure committees', 'batch_2026-05-14T21-27-05_oregon_full_v1'),
  ('8a609810531e9d8b', 'OR', '["federal","state","county","municipal"]', 'recall_rules', 'What is the procedure in Oregon after a recall petition meets the signature threshold?', '["What happens after recall signatures are verified Oregon?","Recall election timeline Oregon","Oregon recall 5-day resignation period"]', 'Once the required number of signatures is verified, the targeted official has five days (excluding weekends/holidays) to resign. If they do not resign, a special recall election must be ordered to take place within 35 days. The official remains in office until the results of the recall election are certified.', 'https://sos.oregon.gov/elections/Pages/recall.aspx', 'Oregon Constitution, Article II, Section 18', '2026-05-14', 'static', 'statute_citation', 'All candidates and campaigns', 'batch_2026-05-14T21-27-05_oregon_full_v1'),
  ('aeb0f66a4fcc779c', 'OR', '["federal","state","county","municipal"]', 'recall_rules', 'Are specific grounds or ''cause'' required to initiate a recall in Oregon?', '["Oregon no-cause recall","Do I need to prove malfeasance for a recall in OR?","Reasons for recall in Oregon"]', 'No specific legal grounds (such as malfeasance or incompetence) are required to initiate a recall in Oregon. Under Article II, Section 18, the petition must state the reasons for the recall in 200 words or less, but the ''truth'' or ''sufficiency'' of those reasons is not subject to court review; the voters are the sole judges of the reasons'' validity.', 'https://sos.oregon.gov/elections/Pages/recall.aspx', 'Oregon Constitution, Article II, Section 18', '2026-05-14', 'static', 'statute_citation', 'All candidates and campaigns', 'batch_2026-05-14T21-27-05_oregon_full_v1'),
  ('32e6ea227a3c8268', 'OR', '["federal"]', 'recall_rules', 'Can U.S. Senators or Representatives be recalled in Oregon?', '["Recalling federal officers in Oregon","Is Jeff Merkley subject to recall?","Does OR state recall apply to Congress?"]', 'No. While the Oregon Constitution allows the recall of ''all public officers,'' federal courts have consistently ruled that state-level recall provisions cannot apply to members of the U.S. Congress, as their qualifications and removal are governed exclusively by the U.S. Constitution.', 'https://sos.oregon.gov/elections/Pages/recall.aspx', 'Oregon Secretary of State - Recall FAQ', '2026-05-14', 'static', 'official_source_direct', 'Federal candidates', 'batch_2026-05-14T21-27-05_oregon_full_v1'),
  ('c1c43bea06dd9e14', 'OR', '["county"]', 'candidate_eligibility', 'What are the eligibility requirements for County Commissioner in Oregon?', '["Qualifications for Oregon County Commissioner","Can I run for county board in OR?","Residency rules for Oregon commissioners"]', 'Under ORS 204.016, a candidate for County Commissioner must be a citizen of the United States, an elector (registered voter) of the county, and have resided in the county for at least one year prior to the election. Some home-rule counties (like Lane or Multnomah) may have additional requirements in their specific county charters.', 'https://oregon.public.law/statutes/ors_204.016', 'ORS 204.016', '2026-05-14', 'static', 'statute_citation', 'County candidates', 'batch_2026-05-14T21-27-05_oregon_full_v1'),
  ('056c2296a8d055b2', 'OR', '["county"]', 'candidate_eligibility', 'Must a District Attorney in Oregon be a licensed attorney?', '["Oregon DA qualifications","Do I need to be a bar member to be a prosecutor in OR?","Eligibility for Oregon District Attorney"]', 'Yes. Per ORS 8.630, a candidate for District Attorney must be a person who has been admitted to practice law in the Supreme Court of Oregon (meaning they must be an active member of the Oregon State Bar) and must be a resident of the state.', 'https://oregon.public.law/statutes/ors_8.630', 'ORS 8.630', '2026-05-14', 'static', 'statute_citation', 'County candidates', 'batch_2026-05-14T21-27-05_oregon_full_v1'),
  ('4869f7342010eacd', 'OR', '["municipal"]', 'candidate_eligibility', 'What are the eligibility requirements for school board candidates in Oregon?', '["Run for school board Oregon requirements","Who can be a school director in OR?","School board residency rules Oregon"]', 'Under ORS 332.018, a candidate for a school district board must be a ''qualified voter'' (registered voter) and must have resided in the district for at least one year immediately preceding the election. They cannot be an employee of the district in which they are running.', 'https://www.osba.org/Resources/Article/Board_Operations/Get_on_Board.aspx', 'Oregon School Boards Association', '2026-05-14', 'static', 'secondary_source', 'School board candidates', 'batch_2026-05-14T21-27-05_oregon_full_v1'),
  ('ae082e0a1fdd21ee', 'OR', '["judicial"]', 'candidate_eligibility', 'How are Oregon Supreme Court and Court of Appeals judges selected?', '["Oregon appellate judge elections","Is the Oregon Supreme Court nonpartisan?","OR judge term lengths"]', 'Justices of the Oregon Supreme Court and judges of the Court of Appeals are elected by the voters in nonpartisan elections for six-year terms. If a midterm vacancy occurs, the Governor appoints a replacement who must then stand for election at the next general election. All judges face mandatory retirement at age 75.', 'https://www.courts.oregon.gov/about/Pages/default.aspx', 'Oregon Judicial Branch', '2026-05-14', 'static', 'official_source_direct', 'Judicial candidates', 'batch_2026-05-14T21-27-05_oregon_full_v1'),
  ('b34034b7fa23f708', 'OR', '["state","federal"]', 'ballot_access', 'How do major party candidates get on the Oregon primary ballot?', '["Oregon primary filing fee vs petition","Getting on the ballot for Oregon Governor","SEL 101 filing Oregon"]', 'Candidates for major party nomination (Democratic or Republican) may choose one of two methods: (1) pay a filing fee, or (2) file by petition. For 2026, candidates must file either Form SEL 101 (fee) or Form SEL 102 (petition) with the Secretary of State by the filing deadline in early March.', 'https://sos.oregon.gov/elections/Pages/candidates.aspx', 'Oregon Secretary of State - Candidate Filing', '2026-05-14', 'per_cycle', 'official_source_direct', 'Major party candidates', 'batch_2026-05-14T21-27-05_oregon_full_v1'),
  ('957c34b946378641', 'OR', '["federal","state"]', 'ballot_access', 'What are the filing fee amounts for Oregon offices?', '["Cost to run for office in Oregon","Oregon Governor filing fee","How much is the filing fee for Oregon legislature?"]', 'As of the 2026 cycle, filing fees are: $150 for U.S. Senator or U.S. Representative; $100 for Governor, Secretary of State, State Treasurer, Attorney General, and BOLI Commissioner; $25 for State Senator or State Representative.', 'https://sos.oregon.gov/elections/Pages/candidates.aspx', 'Oregon Secretary of State - Candidate Filing Fees', '2026-05-14', 'per_cycle', 'official_source_direct', 'All candidates', 'batch_2026-05-14T21-27-05_oregon_full_v1'),
  ('15a420a68eb01163', 'OR', '["federal","state"]', 'ballot_access', 'How do independent or unaffiliated candidates get on the Oregon general election ballot?', '["Independent candidate petition threshold Oregon","Oregon individual elector nomination","How to run for office without a party in Oregon"]', 'Independent (non-affiliated) candidates must use the ''Individual Electors'' process. They must gather valid signatures from registered voters equal to 1% of the total votes cast for Governor in that district/state in the last election. Alternatively, they can be nominated by an ''Assembly of Electors''—a physical meeting of voters (1,000 for statewide, smaller for districts) who sign a nominating certificate.', 'https://sos.oregon.gov/elections/Pages/candidates.aspx', 'Oregon Secretary of State - Candidate Manual', '2026-05-14', 'per_cycle', 'official_source_direct', 'Independent candidates', 'batch_2026-05-14T21-27-05_oregon_full_v1'),
  ('b9b59093d20d0c46', 'OR', '["federal","state","county","municipal"]', 'ballot_access', 'What are the requirements for write-in candidates in Oregon?', '["Do write-in votes count in Oregon?","Oregon write-in candidate registration","Declaration of intent write-in Oregon"]', 'Oregon generally does not require write-in candidates to register before an election. However, under ORS 254.507, write-in votes are only counted and reported if the total number of write-in votes for an office is greater than or equal to the number of votes received by the candidate with the most votes on the ballot, OR if a candidate files a request for a tally.', 'https://oregon.public.law/statutes/ors_254.507', 'ORS 254.507', '2026-05-14', 'static', 'statute_citation', 'Write-in candidates', 'batch_2026-05-14T21-27-05_oregon_full_v1'),
  ('a8a5d053727b7f0b', 'OR', '["state"]', 'ballot_access', 'What is the threshold for a political party to be ''major'' in Oregon?', '["Major vs minor party Oregon","Oregon political party recognition threshold","How many major parties in Oregon?"]', 'A political party is classified as a ''major'' party if its registered voter membership equals at least 5% of the total number of registered voters in the state. Currently, only the Democratic and Republican parties meet this threshold. Major parties are required to nominate candidates via the state-funded primary election.', 'https://sos.oregon.gov/elections/Pages/minor-political-parties.aspx', 'Oregon Secretary of State - Major Parties', '2026-05-14', 'volatile', 'official_source_direct', 'Political parties', 'batch_2026-05-14T21-27-05_oregon_full_v1'),
  ('09587f739948e8c1', 'OR', '["state"]', 'ballot_access', 'Does Oregon have a sore loser law?', '["Can I run as an independent if I lose the OR primary?","Oregon primary defeat independent run","ORS 249.048 sore loser"]', 'Yes. Under ORS 249.048, a person who was a candidate for a major political party in the primary election and was not nominated cannot appear on the general election ballot for the same office as an independent (non-affiliated) candidate or as a nominee of a minor political party.', 'https://oregon.public.law/statutes/ors_249.048', 'ORS 249.048', '2026-05-14', 'static', 'statute_citation', 'Major party candidates', 'batch_2026-05-14T21-27-05_oregon_full_v1'),
  ('2da180d22f23564a', 'OR', '["county","municipal"]', 'election_dates', 'How are county office terms and election cycles structured in Oregon?', '["When are Oregon county officials elected?","Oregon county sheriff term length","Partisan vs nonpartisan county races Oregon"]', 'Most elected county officials—including Commissioners, Sheriffs, Assessors, and Treasurers—serve four-year terms. The vast majority of these offices are nonpartisan and are elected during the same cycle as the Governor (midterm cycle), meaning they will be on the 2026 ballot.', 'https://sos.oregon.gov/elections/Pages/candidates.aspx', 'Oregon Secretary of State - County Elections', '2026-05-14', 'per_cycle', 'official_source_direct', 'County candidates', 'batch_2026-05-14T21-27-05_oregon_full_v1'),
  ('e00ba96bb49187c1', 'OR', '["state","county","municipal"]', 'election_dates', 'What is the canvassing and certification timeline for Oregon elections?', '["When are Oregon election results official?","Oregon certification deadline","ORS 254.545 certification"]', 'Under ORS 254.545, county clerks must complete their official canvass of results and submit them to the Secretary of State no later than the 27th day after the election. The Secretary of State then has until the 30th day after the election to officially certify the statewide results.', 'https://oregon.public.law/statutes/ors_254.545', 'ORS 254.545', '2026-05-14', 'static', 'statute_citation', 'All candidates and campaigns', 'batch_2026-05-14T21-27-05_oregon_full_v1'),
  ('7074fe7cf533700f', 'OR', '["state","county","municipal"]', 'finance_ethics', 'What disclaimer language is required on Oregon campaign materials?', '["Oregon ''Paid for by'' rules","Campaign ad disclaimer requirements Oregon","ORS 260.432 political taglines"]', 'Oregon generally requires political advertisements to include a disclaimer. For materials identifying a candidate, it must include ''Paid for by'' followed by the name of the candidate or committee. For independent expenditures, it must also state that it was not authorized by a candidate or candidate''s committee.', 'https://sos.oregon.gov/elections/Documents/campaign-finance-manual.pdf', 'Oregon Secretary of State - Campaign Finance Manual', '2026-05-14', 'static', 'official_source_direct', 'All candidates and PACs', 'batch_2026-05-14T21-27-05_oregon_full_v1')
